    public Object parseCurrency(Object currency)
    {
        Object currencyId = this.safeString(currency, "coin");
        Object code = this.safeCurrencyCode(currencyId);
        Object name = this.safeString(currency, "name");
        Object chains = this.safeList(currency, "chains", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object networks = new java.util.HashMap<String, Object>() {{}};
        for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(chains)); j++)
        {
            Object chain = Helpers.GetValue(chains, j);
            Object networkId = this.safeString(chain, "chain");
            Object networkCode = this.networkIdToCode(networkId, code);
            Helpers.addElementToObject(networks, networkCode, new java.util.HashMap<String, Object>() {{
    put( "info", chain );
    put( "id", networkId );
    put( "network", networkCode );
    put( "active", null );
    put( "deposit", Helpers.isEqual(BybitCore.this.safeInteger(chain, "chainDeposit"), 1) );
    put( "withdraw", Helpers.isEqual(BybitCore.this.safeInteger(chain, "chainWithdraw"), 1) );
    put( "fee", BybitCore.this.safeNumber(chain, "withdrawFee") );
    put( "precision", BybitCore.this.parseNumber(BybitCore.this.parsePrecision(BybitCore.this.safeString(chain, "minAccuracy"))) );
    put( "limits", new java.util.HashMap<String, Object>() {{
        put( "withdraw", new java.util.HashMap<String, Object>() {{
            put( "min", BybitCore.this.safeNumber(chain, "withdrawMin") );
            put( "max", null );
        }} );
        put( "deposit", new java.util.HashMap<String, Object>() {{
            put( "min", BybitCore.this.safeNumber(chain, "depositMin") );
            put( "max", null );
        }} );
    }} );
}});
        }
        return this.safeCurrencyStructure(new java.util.HashMap<String, Object>() {{
            put( "info", currency );
            put( "code", code );
            put( "id", currencyId );
            put( "name", name );
            put( "active", null );
            put( "deposit", null );
            put( "withdraw", null );
            put( "fee", null );
            put( "precision", null );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "withdraw", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "deposit", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
            }} );
            put( "networks", networks );
            put( "type", "crypto" );
        }});
    }

    /**
     * @method
     * @name bybit#fetchMarkets
     * @description retrieves data on all markets for bybit
     * @see https://bybit-exchange.github.io/docs/v5/market/instrument
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} an array of objects representing market data
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMarkets(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.GetValue(this.options, "adjustForTimeDifference")))
            {
                (this.loadTimeDifference()).join();
            }
            Object promisesUnresolved = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object types = null;
            Object defaultTypes = new java.util.ArrayList<Object>(java.util.Arrays.asList("spot", "linear", "inverse", "option"));
            Object fetchMarketsOptions = this.safeDict(this.options, "fetchMarkets");
            if (Helpers.isTrue(!Helpers.isEqual(fetchMarketsOptions, null)))
            {
                types = this.safeList(fetchMarketsOptions, "types", defaultTypes);
            } else
            {
                // for backward-compatibility
                types = this.safeList(this.options, "fetchMarkets", defaultTypes);
            }
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(types)); i++)
            {
                Object marketType = Helpers.GetValue(types, i);
                if (Helpers.isTrue(Helpers.isEqual(marketType, "spot")))
                {
                    ((java.util.List<Object>)promisesUnresolved).add(this.fetchSpotMarkets(parameters));
                } else if (Helpers.isTrue(Helpers.isEqual(marketType, "linear")))
                {
                    ((java.util.List<Object>)promisesUnresolved).add(this.fetchFutureMarkets(new java.util.HashMap<String, Object>() {{
                        put( "category", "linear" );
                    }}));
                } else if (Helpers.isTrue(Helpers.isEqual(marketType, "inverse")))
                {
                    ((java.util.List<Object>)promisesUnresolved).add(this.fetchFutureMarkets(new java.util.HashMap<String, Object>() {{
                        put( "category", "inverse" );
                    }}));
                } else if (Helpers.isTrue(Helpers.isEqual(marketType, "option")))
                {
                    Object optionsCurrencies = this.safeList(fetchMarketsOptions, "options", new java.util.ArrayList<Object>(java.util.Arrays.asList("BTC", "ETH", "SOL")));
                    for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(optionsCurrencies)); j++)
                    {
                        Object currency = Helpers.GetValue(optionsCurrencies, j);
                        ((java.util.List<Object>)promisesUnresolved).add(this.fetchOptionMarkets(new java.util.HashMap<String, Object>() {{
                            put( "baseCoin", currency );
                        }}));
                    }
                } else
                {
                    throw new ExchangeError((String)Helpers.add(Helpers.add(Helpers.add(this.id, " fetchMarkets() this.options fetchMarkets \""), marketType), "\" is not a supported market type")) ;
                }
            }
            Object promises = (Helpers.promiseAll(promisesUnresolved)).join();
            Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(promises)); i++)
            {
                Object parsedMarket = Helpers.GetValue(promises, i);
                result = this.arrayConcat(result, parsedMarket);
            }
            // const spotMarkets = this.safeList (promises, 0, []);
            // const linearMarkets = this.safeList (promises, 1, []);
            // const inverseMarkets = this.safeList (promises, 2, []);
            // const btcOptionMarkets = this.safeList (promises, 3, []);
            // const ethOptionMarkets = this.safeList (promises, 4, []);
            // const solOptionMarkets = this.safeList (promises, 5, []);
            // const futureMarkets = this.arrayConcat (linearMarkets, inverseMarkets);
            // let optionMarkets = this.arrayConcat (btcOptionMarkets, ethOptionMarkets);
            // optionMarkets = this.arrayConcat (optionMarkets, solOptionMarkets);
            // const derivativeMarkets = this.arrayConcat (futureMarkets, optionMarkets);
            // return this.arrayConcat (spotMarkets, derivativeMarkets);
            return result;
        });

    }

