            //         "time": 1672192792860
            //     }
            //
            Object result = this.safeDict(response, "result", new java.util.HashMap<String, Object>() {{}});
            Object chains = this.safeList(result, "chains", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
