    public Object parseTransactionStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "0", "unknown" );
            put( "1", "pending" );
            put( "2", "processing" );
            put( "3", "ok" );
            put( "4", "fail" );
            put( "SecurityCheck", "pending" );
            put( "Pending", "pending" );
            put( "success", "ok" );
            put( "CancelByUser", "canceled" );
            put( "Reject", "rejected" );
            put( "Fail", "failed" );
            put( "BlockchainConfirmed", "ok" );
        }};
        return this.safeString(statuses, status, status);
    }

    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // fetchWithdrawals
        //
        //     {
        //         "coin": "USDT",
        //         "chain": "TRX",
        //         "amount": "12.34",
        //         "txID": "de5ea0a2f2e59dc9a714837dd3ddc6d5e151b56ec5d786d351c4f52336f80d3c",
        //         "status": "success",
        //         "toAddress": "TQdmFKUoe1Lk2iwZuwRJEHJreTUBoN3BAw",
        //         "tag": "",
        //         "withdrawFee": "0.5",
        //         "createTime": "1665144183000",
        //         "updateTime": "1665144256000",
        //         "withdrawId": "8839035"
        //     }
        //
        // fetchDeposits
        //
        //     {
        //         "coin": "USDT",
        //         "chain": "TRX",
        //         "amount": "44",
        //         "txID": "0b038ea12fa1575e2d66693db3c346b700d4b28347afc39f80321cf089acc960",
        //         "status": "3",
        //         "toAddress": "TC6NCAC5WSVCCiaD3kWZXyW91ZKKhLm53b",
        //         "tag": "",
        //         "depositFee": "",
        //         "successAt": "1665142507000",
        //         "confirmations": "100",
        //         "txIndex": "0",
        //         "blockHash": "0000000002ac3b1064aee94bca1bd0b58c4c09c65813b084b87a2063d961129e"
        //     }
        //
        // withdraw
        //
        //     {
        //         "id": "9377266"
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object currencyId = this.safeString(transaction, "coin");
        Object code = this.safeCurrencyCode(currencyId, currency);
        Object timestamp = this.safeInteger2(transaction, "createTime", "successAt");
        Object updated = this.safeInteger(transaction, "updateTime");
        Object status = this.parseTransactionStatus(this.safeString(transaction, "status"));
        Object feeCost = this.safeNumber2(transaction, "depositFee", "withdrawFee");
        Object type = ((Helpers.isTrue((Helpers.inOp(transaction, "depositFee"))))) ? "deposit" : "withdrawal";
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", code );
            }};
        }
        Object toAddress = this.safeString(transaction, "toAddress");
        final Object finalFee = fee;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", BybitCore.this.safeString2(transaction, "id", "withdrawId") );
            put( "txid", BybitCore.this.safeString(transaction, "txID") );
            put( "timestamp", timestamp );
            put( "datetime", BybitCore.this.iso8601(timestamp) );
            put( "network", BybitCore.this.networkIdToCode(BybitCore.this.safeString(transaction, "chain"), code) );
            put( "address", null );
            put( "addressTo", toAddress );
            put( "addressFrom", null );
            put( "tag", BybitCore.this.safeString(transaction, "tag") );
            put( "tagTo", null );
            put( "tagFrom", null );
            put( "type", type );
            put( "amount", BybitCore.this.safeNumber(transaction, "amount") );
            put( "currency", code );
            put( "status", status );
            put( "updated", updated );
            put( "fee", finalFee );
            put( "internal", null );
            put( "comment", null );
        }};
    }

