    public Object parseConversion(Object conversion, Object... optionalArgs)
    {
        //
        // fetchConvertQuote
        //
        //     {
        //         "quoteTxId": "1010020692439481682687668224",
        //         "exchangeRate": "0.000015330836780000",
        //         "fromCoin": "USDT",
        //         "fromCoinType": "crypto",
        //         "toCoin": "BTC",
        //         "toCoinType": "crypto",
        //         "fromAmount": "10",
        //         "toAmount": "0.000153308367800000",
        //         "expiredTime": "1727257413353",
        //         "requestId": ""
        //     }
        //
        // createConvertTrade
        //
        //     {
        //         "exchangeStatus": "processing",
        //         "quoteTxId": "1010020692439483803499737088"
        //     }
        //
        // fetchConvertTrade, fetchConvertTradeHistory
        //
        //     {
        //         "accountType": "eb_convert_uta",
        //         "exchangeTxId": "1010020692439483803499737088",
        //         "userId": "100406395",
        //         "fromCoin": "USDT",
        //         "fromCoinType": "crypto",
        //         "fromAmount": "10",
        //         "toCoin": "BTC",
        //         "toCoinType": "crypto",
        //         "toAmount": "0.00015344889",
        //         "exchangeStatus": "success",
        //         "extInfo": {},
        //         "convertRate": "0.000015344889",
        //         "createdAt": "1727257904726"
        //     }
        //
        Object fromCurrency = Helpers.getArg(optionalArgs, 0, null);
        Object toCurrency = Helpers.getArg(optionalArgs, 1, null);
        Object timestamp = this.safeInteger2(conversion, "expiredTime", "createdAt");
        Object fromCoin = this.safeString(conversion, "fromCoin");
        Object fromCode = this.safeCurrencyCode(fromCoin, fromCurrency);
        Object to = this.safeString(conversion, "toCoin");
        Object toCode = this.safeCurrencyCode(to, toCurrency);
        return new java.util.HashMap<String, Object>() {{
            put( "info", conversion );
            put( "timestamp", timestamp );
            put( "datetime", BybitCore.this.iso8601(timestamp) );
            put( "id", BybitCore.this.safeString2(conversion, "quoteTxId", "exchangeTxId") );
            put( "fromCurrency", fromCode );
            put( "fromAmount", BybitCore.this.safeNumber(conversion, "fromAmount") );
            put( "toCurrency", toCode );
            put( "toAmount", BybitCore.this.safeNumber(conversion, "toAmount") );
            put( "price", null );
            put( "fee", null );
        }};
    }

